import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import LogoK from '../pictures/LogoK.jpg';

function SplashPage() {
  const [dots, setDots] = useState('...');
  const [isFading, setIsFading] = useState(false);
  const navigate = useNavigate();

  useEffect(() => {
    // Animate the loading dots (0–3 dots cycling)
    const dotInterval = setInterval(() => {
      setDots(prev => (prev.length < 3 ? prev + '.' : ''));
    }, 500);

    // After 3 seconds, fade out then navigate to /home
    const redirectTimer = setTimeout(() => {
      setIsFading(true);
      setTimeout(() => navigate('/home'), 500);
    }, 3000);

    return () => {
      clearInterval(dotInterval);
      clearTimeout(redirectTimer);
    };
  }, [navigate]);

  return (
    <div style={{
      background: 'linear-gradient(135deg, #667eea 0%, #437a9a 100%)',
      height: '100vh',
      display: 'flex',
      justifyContent: 'center',
      alignItems: 'center',
      overflow: 'hidden',
      fontFamily: "'Segoe UI', Tahoma, Geneva, Verdana, sans-serif"
    }}>
      <div
        className={isFading ? 'fade-out' : ''}
        style={{ textAlign: 'center', color: 'white' }}
      >
        {/* Floating logo */}
        <div style={{ marginBottom: '30px', animation: 'float 3s ease-in-out infinite' }}>
          <img
            src={LogoK}
            alt="Logo"
            style={{
              borderRadius: '50%',
              height: '150px',
              width: '150px',
              border: 'none',
              margin: '0 auto'
            }}
          />
        </div>

        <h1 style={{ fontSize: '42px', marginBottom: '20px', textShadow: '2px 2px 4px rgba(0,0,0,0.3)' }}>
          Travel Recap
        </h1>

        {/* Spinner */}
        <div style={{
          width: '80px',
          height: '80px',
          border: '8px solid rgba(255,255,255,0.3)',
          borderTop: '8px solid white',
          borderRadius: '50%',
          margin: '30px auto',
          animation: 'spin 1s linear infinite'
        }} />

        <div style={{ fontSize: '20px', marginTop: '20px', color: 'rgba(255,255,255,0.9)' }}>
          Loading<span style={{ display: 'inline-block', width: '30px', textAlign: 'left' }}>{dots}</span>
        </div>
      </div>

      {/* Inline keyframe styles since these are splash-only animations */}
      <style>{`
        @keyframes float {
          0%, 100% { transform: translateY(0); }
          50% { transform: translateY(-20px); }
        }
        @keyframes spin {
          0% { transform: rotate(0deg); }
          100% { transform: rotate(360deg); }
        }
        @keyframes fadeOut {
          to { opacity: 0; }
        }
        .fade-out {
          animation: fadeOut 0.5s ease-out forwards;
        }
      `}</style>
    </div>
  );
}

export default SplashPage;
